svg.script:
{
  "@context": "https://schema.org",
  "@type": "HowTo",
  "name": "Blocklist Remediation Flow",
  "description": "How to detect, diagnose, and resolve blocklist listings affecting email deliverability.",
  "publisher": {
    "@type": "Organization",
    "name": "InboxAlly",
    "url": "https://www.inboxally.com"
  },
  "step": [
    { "@type": "HowToStep", "position": 1, "name": "Detect Deliverability Drop", "text": "Identify symptoms: inbox placement drops, SMTP blocks increase, bounce rates spike." },
    { "@type": "HowToStep", "position": 2, "name": "Check Blocklists", "text": "Use MXToolbox or multirbl.valli.org to check if your IP or domain is listed." },
    { "@type": "HowToStep", "position": 3, "name": "Identify Blocklist and Severity", "text": "Determine which blocklist and assess severity. Spamhaus SBL/DBL are severe. Spamcop and Barracuda are moderate." },
    { "@type": "HowToStep", "position": 4, "name": "Investigate Root Cause", "text": "Determine why: spam traps, high complaints, compromised account, or purchased list." },
    { "@type": "HowToStep", "position": 5, "name": "Fix Root Cause First", "text": "Resolve the issue before requesting removal. Premature removal leads to relisting." },
    { "@type": "HowToStep", "position": 6, "name": "Request Removal", "text": "Auto-expire (24-48h) or manual request with evidence." },
    { "@type": "HowToStep", "position": 7, "name": "Verify and Monitor", "text": "Verify delisting. If still listed, return to investigation. If clear, monitor for relisting." }
  ]
}
